const err = $input.first().json;
const workflowName = err.workflow?.name || 'unknown';
const nodeName     = err.execution?.lastNodeExecuted || 'unknown';
const errorMsg     = err.execution?.error?.message || 'No error message';
const errorStack   = err.execution?.error?.stack || '';
const execId       = err.execution?.id || 'unknown';
const tenantId     = process.env.TENANT_ID || 'unknown';

console.error(`[error-handler] Workflow: ${workflowName} | Node: ${nodeName} | Error: ${errorMsg}`);

const slackMsg = [
  `🔴 *Revenue OS — Workflow Error*`,
  `*Workflow:* ${workflowName}`,
  `*Failed node:* ${nodeName}`,
  `*Tenant:* ${tenantId}`,
  `*Execution ID:* ${execId}`,
  `*Error:* ${errorMsg.substring(0, 500)}`,
  `*Time:* ${new Date().toISOString()}`,
  '',
  '_Check n8n execution logs for full stack trace._'
].join('\n');

return [{ json: { slack_message: slackMsg, workflow: workflowName, node: nodeName, error: errorMsg, tenant_id: tenantId, exec_id: execId } }];
